(lib.sldr = function(mode,startPosition,loop) {
	this.initialize(mode,startPosition,loop,{});

	// timeline functions:
	this.frame_0 = function() {
		var that = this;
		
		
		
		var isdragged = false;
		 var trkWidth ;
		 var sldWidth  ;
		
		that.rate = 0;
		
		setTimeout(function () {
		
			setListener();
		
			setDimension();
			
		}, 50);
		
		
		function setListener() {
		
			that.minus.addEventListener("click", onMinus);
			that.plus.addEventListener("click", onPlus);
		
			that.trk.addEventListener("pressup", onpressup);
			that.trk.addEventListener("pressmove", onpressmove);
			that.trk.addEventListener("mousedown", onmousedown);
		
		}
		 
		function setDimension(){
			
		  trkWidth = that.trk.getBounds().width;
		  sldWidth = that.sld.getBounds().width;
			
		}
		
		
		function onmousedown(e) {
		
		
			e.nativeEvent.preventDefault();
		
			var pt = that.globalToLocal(e.stageX, e.stageY);
			var posX = pt.x;
			var posY = pt.y;
		
		
		
		}
		
		
		function onpressmove(e) {
		
		
			var pt = that.globalToLocal(e.stageX, e.stageY);
		
		
		
			if (pt.x >= 0 && pt.x <= sldWidth) {
		
				var newX = pt.x;
		
				isdragged = true;
		
		
		
		
				//To prevent quick drag of trk by the user ,we send "dispatchEvent("change")" for eadch mini change of trk.x 
				for (var i = 0; i < Math.abs(that.trk.x - newX); i++) {
		
					var diff = that.trk.x - newX < 0 ? 1 : -1;
		
					that.trk.x += diff;
		
					trkRate(that.trk.x);
		
					that.dispatchEvent("change");
				}
			}
		}
		
		
		//Mouse UP and SNAP====================
		function onpressup(evt) {
		
		
			//var pt = stage.globalToLocal(evt.stageX, evt.stageY);
		
			isdragged = false;
			//evt.currentTarget.x = pt.x;
			//evt.currentTarget.y = pt.y;
			//stage.update(evt);
		
		
		
		}
		
		function onPlus(ev) {
		
			if (that.trk.x < sldWidth) {
		
				scal(4);
			}
		}
		
		function onMinus(ev) {
		
			if (that.trk.x > 0) {
		
				scal(-4);
			}
		}
		
		function scal(scalMainusAndPlus) {
		
		
			//To prevent quick drag of trk by the user ,we send "dispatchEvent("change")" for eadch mini change of trk.x 
			for (var i = 0; i < Math.abs(scalMainusAndPlus); i++) {
		
				var diff = scalMainusAndPlus > 0 ? 1 : -1;
		
		
				console.log("scalMainusAndPlus " + i);
		
				if (diff == 1 && that.trk.x < sldWidth) {
		
					that.trk.x += diff;
		
					trkRate(that.trk.x);
		
					that.dispatchEvent("change");
		
		
				}
				if (diff == -1 && that.trk.x > 0) {
		
					that.trk.x += diff;
		
					trkRate(that.trk.x);
		
					that.dispatchEvent("change");
				}
			}
		
		
		
		}
		function trkRate(currentPosition) {
		
			var cur = currentPosition < 0 ? 0 : currentPosition > sldWidth ? sldWidth : currentPosition;
			that.rate = cur / sldWidth * 3;
			return that.rate;
		}
		
		that.resetTrk = function () {
		
		
			that.trk.x = 0;
			that.rate = 0;
		
		
		}
	}

	// actions tween:
	this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(1));

	// Layer_2
	this.trk = new lib.trk();
	this.trk.name = "trk";
	this.trk.parent = this;
	this.trk.setTransform(0,6.25,0.6458,1);

	this.timeline.addTween(cjs.Tween.get(this.trk).wait(1));

	// Layer_1
	this.sld = new lib.sld();
	this.sld.name = "sld";
	this.sld.parent = this;
	this.sld.setTransform(101,7.15,1,1,0,0,0,103,4.1);

	this.timeline.addTween(cjs.Tween.get(this.sld).wait(1));

	// Layer_3
	this.plus = new lib.plusAndminus();
	this.plus.name = "plus";
	this.plus.parent = this;
	this.plus.setTransform(226.5,6.7);

	this.minus = new lib.plusAndminus();
	this.minus.name = "minus";
	this.minus.parent = this;
	this.minus.setTransform(-21.4,6.7);

	this.timeline.addTween(cjs.Tween.get({}).to({state:[{t:this.minus},{t:this.plus}]}).wait(1));

}).prototype = getMCSymbolPrototype(lib.sldr, new cjs.Rectangle(-34.5,-11.7,274.4,35.599999999999994), null);


