	this.zm1.setTransform(119.25,335,1.5748,1.445);

	this.timeline.addTween(cjs.Tween.get({}).to({state:[{t:this.c1},{t:this.c2}]}).to({state:[{t:this.zm1},{t:this.zm2},{t:this.zm3},{t:this.zm4},{t:this.zm5}]},1).wait(1));

