(lib.sld_mc = function(mode,startPosition,loop) {
	this.initialize(mode,startPosition,loop,{});

	// timeline functions:
	this.frame_0 = function() {
		var that = this;
		
		
		var currentevent;
		var isfirst;
		var soundIsReady;
		var soundEnd;
		var duration;
		
		
		that.cursor.mouseEnabled = false;
		
		if (!createjs.Sound.isReady()) {
			// createjs.FlashAudioPlugin.swfPath = "../src/soundjs/flashaudio/";
			createjs.Sound.registerPlugins([createjs.WebAudioPlugin, createjs.HTMLAudioPlugin, createjs.FlashAudioPlugin]);
		}
		
		
		
		
		(function startGame() {
		
		
			// if initializeDefaultPlugins returns false, we cannot play sound in this browser
			//if (!createjs.Sound.initializeDefaultPlugins()) {
			//	return;
			//}
		
			/*	var audioPath = "mysound/";
			var sounds = [
		
				{
					id: "d1",
					src: "sout.mp3"
				}
			];
		
			createjs.Sound.alternateExtensions = ["ogg"];
		
			createjs.Sound.addEventListener("fileload", handleLoad);
			createjs.Sound.registerSounds(sounds, audioPath);
			*/
		
			//	createjs.Sound.registerPlugins([createjs.WebAudioPlugin, createjs.FlashAudioPlugin]);
			createjs.Sound.alternateExtensions = ["ogg"];
			createjs.Sound.addEventListener("fileload", handleLoad);
		
			soundIsReady = createjs.Sound.registerSound("mysound/sout.mp3", "sound");
		
		})();
		
		
		
		function handleLoad(event) {
		
		
			soundIsReady = true;
		
		}
		
		
		//************************* MUSIC BUTTON  ************************  
		
		that.musicBtn.addEventListener("click", musicToggle);
		
		var on = true;
		
		function musicToggle(eve) {
		
			if (eve.nativeEvent instanceof MouseEvent) {
		
				if (on && soundIsReady) {
		
					that.musicBtn.musicOn.visible = false;
					that.musicBtn.musicOff.visible = true;
		
					if (!isfirst) {
		
						that.music = createjs.Sound.play("sound");
		
		
						that.music.on("complete", handleComplete);
		
						duration = that.music.duration;
		
						that.parent.mov.gotoAndPlay(0);
		
						isfirst = true;
		
		
					}
		
					that.parent.mov.play();
		
		
					if (soundEnd) {
		
						that.music.play();
		
						soundEnd = false;
					}
		
		
		
					resetSoundPosition(that.cursor.rate);
		
					that.music.paused = false;
		
					on = false;
		
		
					console.log("mov.currentFrame : " + that.parent.mov.currentFrame);
		
					that.cursor.mouseEnabled = true;
		
				} else if (soundIsReady) {
		
					that.musicBtn.musicOn.visible = true;
					that.musicBtn.musicOff.visible = false;
					that.music.paused = true;
					on = true;
		
					that.parent.mov.stop();
		
					that.cursor.mouseEnabled = false;
				}
			}
		}
		
		
		function resetSoundPosition(rate) {
		
			that.music.setPosition(duration * rate);
		
		}
		
		that.resetSoundPosition = resetSoundPosition;
		
		
		
		createjs.Ticker.on("tick", updateTRK);
		
		function updateTRK() {
		
			if (isfirst) {
		
				that.cursor.resetTrk(that.music.getPosition() / duration);
		
			}
		}
		
		
		function handleComplete() {
		
			soundEnd = true;
		
			that.parent.mov.gotoAndStop(0);
			that.cursor.mouseEnabled = false;
		
			that.musicBtn.musicOn.visible = true;
			that.musicBtn.musicOff.visible = false;
		
			on = true;
		
		}
		
		that.parent.addEventListener("removed", removeListeners);
		
		function removeListeners(e) {
		
			createjs.Sound.stop();
		
			createjs.Sound.removeEventListener("fileload", handleLoad);
			that.musicBtn.removeEventListener("click", musicToggle);
			that.parent.removeEventListener("removed", removeListeners);
		}
	}

	// actions tween:
	this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(1));

	// Layer_2
	this.musicBtn = new lib.btn();
	this.musicBtn.name = "musicBtn";
	this.musicBtn.parent = this;
	this.musicBtn.setTransform(74.15,9.25);

	this.timeline.addTween(cjs.Tween.get(this.musicBtn).wait(1));

	// Layer_3
	this.cursor = new lib.mini_slder();
	this.cursor.name = "cursor";
	this.cursor.parent = this;
	this.cursor.setTransform(238.75,41.85,1,1,0,0,0,107.1,16.3);

	this.timeline.addTween(cjs.Tween.get(this.cursor).wait(1));

}).prototype = getMCSymbolPrototype(lib.sld_mc, new cjs.Rectangle(70.5,6.6,267.5,36.3), null);


