			function AddRorL(MCC) {
		
				var dist = {};
		
				var ts = MCC.name.slice(0, 1);
		
				if (ts === "L") {
		
					dist.x = MCC.getBounds().width / 2;
					dist.y = 0;
		
				} else if (ts === "R") {
		
					dist.x = 0 - MCC.getBounds().width / 2;
					dist.y = 0;
				}
		
		
				if (ts === "T") {
		
					dist.x = 0;
					dist.y = MCC.getBounds().height / 2;
		
				} else if (ts === "B") {
		
					dist.x = 0;
					dist.y = 0 - MCC.getBounds().height / 2;
				}
		
				return dist;
			}
		
		
